from sympy.ntheory.factor_ import core
def P(n): return core(n) < n
reach = {4, 8, 9}
for d in range(1, 10001):
    print(len(reach), end=", ")
    newreach = set()
    for q in reach:
        for digit in range(10):
            t = 10*q + digit
            if P(t):
                newreach.add(t)
    reach = newreach
